class Solution:
    def round_to_perfect_square(self, n: int) -> int:
        low, high = 1, n
        while low <= high:
            mid = low + (high - low) // 2
            square = mid * mid
            if square == n:
                return square
            elif square < n:
                low = mid + 1
            else:
                high = mid - 1
        return low * low

    def main(self):
        try:
            n = int(input())
            result = self.round_to_perfect_square(n)
            print(result)
        except Exception as e:
            print('Error:', str(e))

    if __name__ == '__main__':
        self.main()

solutions.cpp:
class Solution {
public:
    int round_to_perfect_square(int n) {
        low = 1;
        high = n;
        while (low <= high) {
            mid = low + (high - low) / 2;
            square = mid * mid;
            if (square == n) return square;
            else if (square < n) low = mid + 1;
            else high = mid - 1;
        }
        return low * low;
    }

    int main() {
        int n;
        std::cin >> n;
        int result = round_to_perfect_square(n);
        std::cout << result << std::endl;
        return 0;
    }
};
